import React, {Component} from 'react'
import './style.css'
import Article from '../article'
import accordion from '../../decorators/accordion'
import {connect} from 'react-redux'
import {filteredArticlesSelector, loadedSelector, loadingSelector} from '../../selectors'
import {loadAllArticles} from '../../actions'
import Loader from '../common/loader'
import {NavLink} from 'react-router-dom'

class ArticleList extends Component {
    componentDidMount() {
        !this.props.loaded && this.props.fetchData && this.props.fetchData()
    }

    render() {
        console.log('render article list')
        const {
            openItemId,
            toggleOpenItem,
            articles,
            loading
        } = this.props

        const articleList = articles.map(article =>
            <li key={article.id} className="article-list__li">
                <NavLink to={`/articles/${article.id}`}>{article.title}</NavLink>
                {/*<Article
                    article={article}
                    isOpen={openItemId === article.id}
                    toggleArticle={toggleOpenItem}
                />*/}
            </li>
        )

        return (
            loading ?
                <Loader/> :
                <ul>{articleList}</ul>
        )
    }
}

export default connect(
    state => {
        console.log('articles list connect')
        return {
            articles: filteredArticlesSelector(state),
            loading: loadingSelector(state),
            loaded: loadedSelector(state)

        }
    },
    {
        fetchData: loadAllArticles
    }
)(accordion(ArticleList))
